"""A readable parser for standard 5-field cron expressions.

The public entry point is `parse`, which turns a cron string such as
"0 12 * * 1-5" into a CronExpression. That object exposes the parsed values for
each field and a describe() method that renders a human-readable summary.

The code is organised top-down: data definitions first, then field parsing,
then the top-level parser, then description rendering.
"""

from __future__ import annotations

from dataclasses import dataclass


class CronParseError(ValueError):
    """Raised when a cron expression cannot be parsed."""


# ---------------------------------------------------------------------------
# Field definitions
# ---------------------------------------------------------------------------
# Every cron field is the same problem with different bounds and labels, so we
# describe each field once as data and reuse a single parser for all of them.


@dataclass(frozen=True)
class FieldSpec:
    """The static rules for one cron field (its name and valid value range)."""

    name: str
    min_value: int
    max_value: int

    def validate(self, value: int) -> int:
        """Return *value* if it lies within this field's range, else raise."""
        if not self.min_value <= value <= self.max_value:
            raise CronParseError(
                f"{self.name} value {value} is out of range "
                f"({self.min_value}-{self.max_value})"
            )
        return value


MINUTE = FieldSpec("minute", 0, 59)
HOUR = FieldSpec("hour", 0, 23)
DAY_OF_MONTH = FieldSpec("day_of_month", 1, 31)
MONTH = FieldSpec("month", 1, 12)
DAY_OF_WEEK = FieldSpec("day_of_week", 0, 6)

FIELD_SPECS: tuple[FieldSpec, ...] = (MINUTE, HOUR, DAY_OF_MONTH, MONTH, DAY_OF_WEEK)


# ---------------------------------------------------------------------------
# Field terms
# ---------------------------------------------------------------------------
# A field is a comma-separated list of "terms". Each term is one of four shapes.
# Modelling them as small classes keeps both value-expansion and description
# rendering simple: each class knows how to expand itself into concrete values,
# and the describer can pattern-match on the class.


class Term:
    """One comma-separated piece of a field (`*`, `5`, `1-9`, `*/2`)."""

    def values(self, spec: FieldSpec) -> set[int]:
        """Expand this term into the concrete integers it matches."""
        raise NotImplementedError


@dataclass(frozen=True)
class Wildcard(Term):
    """The `*` term: matches every value in the field's range."""

    def values(self, spec: FieldSpec) -> set[int]:
        return set(range(spec.min_value, spec.max_value + 1))


@dataclass(frozen=True)
class Single(Term):
    """A single value such as `42`."""

    value: int

    def values(self, spec: FieldSpec) -> set[int]:
        return {self.value}


@dataclass(frozen=True)
class RangeTerm(Term):
    """An inclusive range such as `1-5`."""

    start: int
    end: int

    def values(self, spec: FieldSpec) -> set[int]:
        return set(range(self.start, self.end + 1))


@dataclass(frozen=True)
class StepTerm(Term):
    """A stepped range such as `*/15` or `1-30/5` (every *step*-th value)."""

    start: int
    end: int
    step: int

    def values(self, spec: FieldSpec) -> set[int]:
        return set(range(self.start, self.end + 1, self.step))

    def covers_full_range(self, spec: FieldSpec) -> bool:
        """True when the step spans the field's entire range (e.g. `*/15`)."""
        return self.start == spec.min_value and self.end == spec.max_value


# ---------------------------------------------------------------------------
# Parsing a single term
# ---------------------------------------------------------------------------
# These helpers each handle exactly one term shape. parse_term dispatches to
# them in priority order: step, range, wildcard, single.


def parse_int(text: str, spec: FieldSpec) -> int:
    """Parse and range-check a single integer literal from a field."""
    try:
        value = int(text)
    except ValueError:
        raise CronParseError(f"{spec.name}: {text!r} is not a valid integer")
    return spec.validate(value)


def parse_step(token: str, spec: FieldSpec) -> StepTerm:
    """Parse a `base/step` token where base is `*` or a range."""
    base, _, step_text = token.partition("/")

    try:
        step = int(step_text)
    except ValueError:
        raise CronParseError(f"{spec.name}: {step_text!r} is not a valid step")
    if step < 1:
        raise CronParseError(f"{spec.name}: step must be 1 or greater, got {step}")

    if base == "*":
        return StepTerm(spec.min_value, spec.max_value, step)

    start, end = parse_range_bounds(base, spec)
    return StepTerm(start, end, step)


def parse_range_bounds(token: str, spec: FieldSpec) -> tuple[int, int]:
    """Parse the `start-end` part of a range and confirm start <= end."""
    start_text, _, end_text = token.partition("-")
    start = parse_int(start_text, spec)
    end = parse_int(end_text, spec)
    if start > end:
        raise CronParseError(
            f"{spec.name}: range start {start} is greater than end {end}"
        )
    return start, end


def parse_term(token: str, spec: FieldSpec) -> Term:
    """Parse one comma-separated token into the appropriate Term subclass."""
    if not token:
        raise CronParseError(f"{spec.name}: empty value (check for stray commas)")
    if "/" in token:
        return parse_step(token, spec)
    if "-" in token:
        return RangeTerm(*parse_range_bounds(token, spec))
    if token == "*":
        return Wildcard()
    return Single(parse_int(token, spec))


# ---------------------------------------------------------------------------
# Parsing a whole field
# ---------------------------------------------------------------------------


@dataclass(frozen=True)
class CronField:
    """One parsed field: its spec, the original text, and its terms."""

    spec: FieldSpec
    raw: str
    terms: tuple[Term, ...]

    @property
    def values(self) -> tuple[int, ...]:
        """All matching values for this field, sorted ascending."""
        matched: set[int] = set()
        for term in self.terms:
            matched |= term.values(self.spec)
        return tuple(sorted(matched))

    @property
    def is_wildcard(self) -> bool:
        """True when the field is a bare `*` (matches everything)."""
        return len(self.terms) == 1 and isinstance(self.terms[0], Wildcard)


def parse_field(raw: str, spec: FieldSpec) -> CronField:
    """Parse one cron field (a comma-separated list of terms)."""
    terms = tuple(parse_term(token, spec) for token in raw.split(","))
    return CronField(spec=spec, raw=raw, terms=terms)


# ---------------------------------------------------------------------------
# Top-level expression
# ---------------------------------------------------------------------------


@dataclass(frozen=True)
class CronExpression:
    """A fully parsed 5-field cron expression."""

    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    @property
    def fields(self) -> tuple[CronField, ...]:
        """The five fields in cron order."""
        return (
            self.minute,
            self.hour,
            self.day_of_month,
            self.month,
            self.day_of_week,
        )

    def describe(self) -> str:
        """Render a human-readable English description of the schedule."""
        return describe_expression(self)


def parse(expression: str) -> CronExpression:
    """Parse a standard 5-field cron expression into a CronExpression."""
    tokens = expression.split()
    if len(tokens) != len(FIELD_SPECS):
        raise CronParseError(
            f"expected {len(FIELD_SPECS)} fields, got {len(tokens)}: {expression!r}"
        )

    minute, hour, day_of_month, month, day_of_week = (
        parse_field(token, spec) for token, spec in zip(tokens, FIELD_SPECS)
    )
    return CronExpression(
        minute=minute,
        hour=hour,
        day_of_month=day_of_month,
        month=month,
        day_of_week=day_of_week,
    )


# ---------------------------------------------------------------------------
# Description rendering
# ---------------------------------------------------------------------------
# describe_expression first checks for a few idiomatic whole-expression shapes
# ("every minute", "every N minutes", "every N hours"), then falls back to
# composing a clause per field: "At <time> [on <day-of-month>] [on <weekdays>]
# [in <months>]".

WEEKDAY_NAMES = (
    "Sunday",
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday",
)
MONTH_NAMES = (
    "January",
    "February",
    "March",
    "April",
    "May",
    "June",
    "July",
    "August",
    "September",
    "October",
    "November",
    "December",
)


def describe_expression(expr: CronExpression) -> str:
    """Produce the English description, trying idioms before the general form."""
    idiom = describe_common_interval(expr)
    if idiom is not None:
        return idiom

    clauses = [f"At {describe_time(expr)}"]
    clauses += describe_day_clauses(expr)
    return " ".join(clauses)


def describe_common_interval(expr: CronExpression) -> str | None:
    """Handle the recurring-interval idioms, or return None if none apply."""
    others_wild = all(
        field.is_wildcard
        for field in (expr.hour, expr.day_of_month, expr.month, expr.day_of_week)
    )

    if expr.minute.is_wildcard and others_wild:
        return "Every minute"

    minute_step = single_full_step(expr.minute)
    if minute_step is not None and others_wild:
        return f"Every {minute_step} minutes"

    hour_step = single_full_step(expr.hour)
    day_and_date_wild = all(
        field.is_wildcard
        for field in (expr.day_of_month, expr.month, expr.day_of_week)
    )
    if single_value(expr.minute) == 0 and hour_step is not None and day_and_date_wild:
        return f"Every {hour_step} hours, on the hour"

    return None


def describe_time(expr: CronExpression) -> str:
    """Describe the minute/hour portion as a clock time where possible."""
    minute = single_value(expr.minute)
    hour = single_value(expr.hour)

    if minute is not None and hour is not None:
        if hour == 0 and minute == 0:
            return "midnight"
        return f"{hour:02d}:{minute:02d}"

    if minute is not None and expr.hour.is_wildcard:
        return f"{minute} minutes past every hour"

    return (
        f"minute(s) {format_number_list(expr.minute.values)} "
        f"of hour(s) {format_number_list(expr.hour.values)}"
    )


def describe_day_clauses(expr: CronExpression) -> list[str]:
    """Build the day-of-month, weekday, and month clauses (only when present)."""
    clauses: list[str] = []

    if not expr.day_of_month.is_wildcard:
        clause = "on the " + describe_days_of_month(expr.day_of_month)
        if expr.month.is_wildcard:
            clause += " of every month"
        clauses.append(clause)

    if not expr.day_of_week.is_wildcard:
        clauses.append("on " + describe_weekdays(expr.day_of_week))

    if not expr.month.is_wildcard:
        clauses.append("in " + describe_months(expr.month))

    return clauses


def describe_days_of_month(field: CronField) -> str:
    """Describe day-of-month values as ordinals (e.g. `1st, 15th, and 30th`)."""
    return join_with_and([ordinal(day) for day in field.values])


def describe_weekdays(field: CronField) -> str:
    """Describe weekday values, using "X through Y" for a single range term."""
    range_term = single_range_term(field)
    if range_term is not None:
        return (
            f"{WEEKDAY_NAMES[range_term.start]} "
            f"through {WEEKDAY_NAMES[range_term.end]}"
        )
    return join_with_and([WEEKDAY_NAMES[day] for day in field.values])


def describe_months(field: CronField) -> str:
    """Describe month values, using "X through Y" for a single range term."""
    range_term = single_range_term(field)
    if range_term is not None:
        return (
            f"{MONTH_NAMES[range_term.start - 1]} "
            f"through {MONTH_NAMES[range_term.end - 1]}"
        )
    return join_with_and([MONTH_NAMES[month - 1] for month in field.values])


# ---------------------------------------------------------------------------
# Small description helpers
# ---------------------------------------------------------------------------


def single_value(field: CronField) -> int | None:
    """Return the value when a field is exactly one literal value, else None."""
    if len(field.terms) == 1 and isinstance(field.terms[0], Single):
        return field.terms[0].value
    return None


def single_full_step(field: CronField) -> int | None:
    """Return the step when a field is a single full-range step (e.g. `*/15`)."""
    if len(field.terms) == 1 and isinstance(field.terms[0], StepTerm):
        step_term = field.terms[0]
        if step_term.covers_full_range(field.spec):
            return step_term.step
    return None


def single_range_term(field: CronField) -> RangeTerm | None:
    """Return the term when a field is exactly one range (e.g. `1-5`), else None."""
    if len(field.terms) == 1 and isinstance(field.terms[0], RangeTerm):
        return field.terms[0]
    return None


def ordinal(number: int) -> str:
    """Format an integer as an English ordinal (1 -> "1st", 22 -> "22nd")."""
    if 11 <= number % 100 <= 13:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(number % 10, "th")
    return f"{number}{suffix}"


def join_with_and(items: list[str]) -> str:
    """Join items with commas and a final "and" (Oxford comma for 3+)."""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return ", ".join(items[:-1]) + f", and {items[-1]}"


def format_number_list(values: tuple[int, ...]) -> str:
    """Join numbers with the same Oxford-comma rules as join_with_and."""
    return join_with_and([str(value) for value in values])


# ---------------------------------------------------------------------------
# Manual check against the documented examples
# ---------------------------------------------------------------------------

if __name__ == "__main__":
    examples = {
        "* * * * *": "Every minute",
        "0 12 * * 1-5": "At 12:00 on Monday through Friday",
        "*/15 * * * *": "Every 15 minutes",
        "0 0 1 * *": "At midnight on the 1st of every month",
        "30 8 * * 1,3,5": "At 08:30 on Monday, Wednesday, and Friday",
        "0 */2 * * *": "Every 2 hours, on the hour",
    }
    for expression, expected in examples.items():
        actual = parse(expression).describe()
        status = "ok " if actual == expected else "FAIL"
        print(f"[{status}] {expression!r:18} -> {actual!r}")
