# Human description helpers
# =============================================================================


def _ordinal(n: int) -> str:
    """Return ordinal form: 1 -> '1st', 2 -> '2nd', 11 -> '11th'."""
    if 11 <= n % 100 <= 13:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(n % 10, "th")
    return f"{n}{suffix}"


def _format_time(hour: int, minute: int) -> str:
    """Format as HH:MM with zero padding."""
    return f"{hour:02d}:{minute:02d}"


def _english_list(items: list[str]) -> str:
    """Join strings into natural English: ['A'] -> 'A', ['A','B'] -> 'A and B'."""
    if not items:
        return ""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return ", ".join(items[:-1]) + f", and {items[-1]}"


def _is_contiguous_range(values: list[int]) -> bool:
    """Return True if the sorted values form an unbroken range."""
    if len(values) < 2:
        return False
    return values == list(range(values[0], values[-1] + 1))


def _capitalize_first(text: str) -> str:
    """Capitalize the first character of a non-empty string."""
    if not text:
        return text
    return text[0].upper() + text[1:]


def _describe_values(
    field: CronField,
    formatter: Callable[[int], str],
) -> str:
    """Describe the set of allowed values using the given formatter.

    Returns things like 'every', 'Monday through Friday', or '1st, 15th, and 20th'.
    """
    if field.is_wildcard:
        return "every"

    values = sorted(field.allowed_values)
    if len(values) == 1:
        return formatter(values[0])

    if _is_contiguous_range(values):
        return f"{formatter(values[0])} through {formatter(values[-1])}"

    return _english_list([formatter(v) for v in values])


def _get_single_value(field: CronField) -> int:
    """Return the one value when is_single_value is known to be True."""
    return next(iter(field.allowed_values))


